def fibonacci(n):
    if n <= 1:
        return n
    return fibonacci(n - 1) + fibonacci(n - 2)

public String fetchAllData(List<String> urls) throws Exception {
    StringBuilder sb = new StringBuilder();
    for (String url : urls) {
        HttpURLConnection conn = (HttpURLConnection) new URL(url).openConnection();
        sb.append(new String(conn.getInputStream().readAllBytes()));
    }
    return sb.toString();
}

