@dataclass(frozen=True)
class Money:
    amount: Decimal
    currency: str = 'USD'

    def __add__(self, other: 'Money') -> 'Money':
        if self.currency != other.currency:
            raise ValueError(f'Cannot add {self.currency} and {other.currency}')
        return Money(self.amount + other.amount, self.currency)

const rateLimit = (maxRequests, windowMs) => {
    const hits = new Map();
    return (req, res, next) => {
        const key = req.ip;
        const now = Date.now();
        const record = hits.get(key) || { count: 0, start: now };
        if (now - record.start > windowMs) {
            record.count = 0; record.start = now;
        }
        if (++record.count > maxRequests) return res.status(429).end();
        hits.set(key, record);
        next();
    };
};

def chunked(iterable, size: int):
    it = iter(iterable)
    while chunk := list(islice(it, size)):
        yield chunk

def retry(max_attempts: int = 3, delay: float = 1.0):
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            for attempt in range(max_attempts):
                try:
                    return func(*args, **kwargs)
                except Exception:
                    if attempt == max_attempts - 1:
                        raise
                    time.sleep(delay * (2 ** attempt))
        return wrapper
    return decorator

class ErrorBoundary extends React.Component {
    state = { error: null };
    static getDerivedStateFromError(error) { return { error }; }
    componentDidCatch(error, info) { logService.report(error, info); }
    render() {
        return this.state.error
            ? <FallbackUI error={this.state.error} />
            : this.props.children;
    }
}

private final ConcurrentHashMap<String, AtomicLong> counters = new ConcurrentHashMap<>();

public long increment(String key) {
    return counters.computeIfAbsent(key, k -> new AtomicLong(0)).incrementAndGet();
}

function debounce(fn, ms) {
    let timer;
    return (...args) => {
        clearTimeout(timer);
        timer = setTimeout(() => fn.apply(this, args), ms);
    };
}

public record PageRequest(int page, int size) {
    public PageRequest {
        if (page < 0) throw new IllegalArgumentException("page must be >= 0");
        if (size < 1 || size > 100) throw new IllegalArgumentException("size must be 1-100");
    }
    public int offset() { return page * size; }
}
